from ultralytics import YOLO

print("Loading SYNTHETIC model weights...")
# Point this to the weights generated by your first training run
model = YOLO("/export/data/lriethm/CV_Project/yolo_runs/sim2real_v1-2/weights/last.pt")

print("Evaluating on REAL test data...")
# Point this to the yaml file Roboflow just downloaded
metrics = model.val(
    data="/export/data/lriethm/CV_Project/datasets/real_origami/data.yaml", 
    split="test", # Force it to only look at the 30 test images
    plots=True    # Generates visual charts and confusion matrices
)

print(f"mAP50-95: {metrics.box.map}") # Prints your final accuracy score!